SELECT COUNT(user_id) AS active_user_count 
FROM users 
WHERE is_active = TRUE;

SELECT category_id, name 
FROM categories 
WHERE parent_id IS NULL;

SELECT txn_type, AVG(amount) AS average_amount 
FROM transactions 
GROUP BY txn_type;

SELECT l.loan_id, l.outstanding, l.dpd, l.npa_flag 
FROM loans l 
WHERE l.npa_flag = TRUE AND l.outstanding > 100000;

SELECT AVG(attempts_per_parcel) 
FROM (
  SELECT parcel_id, COUNT(attempt_id) AS attempts_per_parcel
  FROM delivery_attempts
  GROUP BY parcel_id
) AS subquery;
